package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.apache.commons.csv.CSVFormat;

class CSVFormatTest {

    @Test
    void testGetRecordSeparator_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertEquals("\r\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_CustomString() {
        CSVFormat format = CSVFormat.DEFAULT.withRecordSeparator("|\n");
        assertEquals("|\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_CustomChar() {
        CSVFormat format = CSVFormat.DEFAULT.withRecordSeparator('\n');
        assertEquals("\n", format.getRecordSeparator());
    }

    @Test
    void testGetRecordSeparator_Null() throws Exception {
        // Use reflection to create CSVFormat with null recordSeparator
        var constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, 
            Enum.class, Character.class, Character.class, boolean.class, boolean.class, String.class, 
            String.class, Object[].class, String[].class, boolean.class, boolean.class, boolean.class);
        constructor.setAccessible(true);
        CSVFormat format = (CSVFormat) constructor.newInstance(
            ',', '"', null, null, null, false, true, null, null, null, null, false, false, false);
        assertNull(format.getRecordSeparator());
    }
}
